package com.example.usage;

import com.seed.api.SeedApiClient;

public class Example {
    public static void main(String[] args) {
        SeedApiClient client = SeedApiClient
            .builder()
            .token("<token>")
            .apiKey("<X-Api-Key>")
            .build();

        client.v1().listUsers();
    }
}

